# Configuration
my $SESSION_DIR     = '/tmp';
my $SESSION_PREFIX  = 'sess_';
my $SESSION_COOKIE  = 'PERLSESSID';
my $SESSION_EXPIRE  = 3600;  # 1 hour in seconds

# --- Session Management Package ---
package Session;

sub new {
    my ($class, %opts) = @_;
    my $self = bless {
        session_dir    => $opts{session_dir}    || $SESSION_DIR,
        session_prefix => $opts{session_prefix} || $SESSION_PREFIX,
        cookie_name    => $opts{cookie_name}    || $SESSION_COOKIE,
        expire         => $opts{expire}         || $SESSION_EXPIRE,
        cgi            => $opts{cgi}            || CGI->new(),
        session_id     => undef,
        data           => {},
        is_new         => 0,
    }, $class;

    $self->_init();
    return $self;
}

sub _init {
    my ($self) = @_;

    # Ensure session directory exists
    unless (-d $self->{session_dir}) {
        mkdir $self->{session_dir}, 0700
            or die "Cannot create session directory $self->{session_dir}: $!";
    }

    # Try to get session ID from cookie
    my %cookies = CGI::Cookie->fetch();
    if ($cookies{$self->{cookie_name}}) {
        my $candidate_id = $cookies{$self->{cookie_name}}->value;

        # Validate session ID format (only hex characters allowed)
        if ($candidate_id && $candidate_id =~ /^[a-f0-9]{64}$/) {
            $self->{session_id} = $candidate_id;
        }
    }

    # Load existing session or create new one
    if ($self->{session_id} && $self->_session_file_exists()) {
        $self->_load();
    } else {
        $self->_create();
    }

    # Clean up expired sessions periodically (1 in 100 chance)
    if (int(rand(100)) == 0) {
        $self->_cleanup_expired();
    }
}

sub _generate_session_id {
    my ($self) = @_;
    my $random_data = join('', map { chr(int(rand(256))) } 1..32);
    my $unique = time() . $$ . $random_data . rand();
    return Digest::SHA::sha256_hex($unique);
}

sub _session_file_path {
    my ($self) = @_;
    return File::Spec->catfile(
        $self->{session_dir},
        $self->{session_prefix} . $self->{session_id}
    );
}

sub _session_file_exists {
    my ($self) = @_;
    my $file = $self->_session_file_path();
    return -f $file;
}

sub _create {
    my ($self) = @_;
    $self->{session_id} = $self->_generate_session_id();
    $self->{data} = {
        _created  => time(),
        _modified => time(),
        _expire   => $self->{expire},
    };
    $self->{is_new} = 1;
    $self->_save();
}

sub _load {
    my ($self) = @_;
    my $file = $self->_session_file_path();

    eval {
        $self->{data} = Storable::lock_retrieve($file);
    };

    if ($@ || !$self->{data}) {
        warn "Failed to load session $self->{session_id}: $@";
        $self->_create();
        return;
    }

    # Check if session has expired
    my $modified = $self->{data}{_modified} || 0;
    my $expire   = $self->{data}{_expire}   || $self->{expire};

    if ((time() - $modified) > $expire) {
        warn "Session $self->{session_id} has expired, creating new session";
        $self->destroy();
        $self->_create();
        return;
    }

    # Update modification time
    $self->{data}{_modified} = time();
    $self->{is_new} = 0;
}

sub _save {
    my ($self) = @_;
    my $file = $self->_session_file_path();

    $self->{data}{_modified} = time();

    eval {
        Storable::lock_nstore($self->{data}, $file);
    };

    if ($@) {
        die "Failed to save session $self->{session_id}: $@";
    }

    # Set file permissions to be readable only by owner
    chmod 0600, $file;
}

sub get {
    my ($self, $key) = @_;
    return $self->{data}{$key};
}

sub set {
    my ($self, $key, $value) = @_;

    # Prevent overwriting internal keys accidentally
    if ($key =~ /^_/ && $key !~ /^_(created|modified|expire)$/) {
        # Allow user keys starting with underscore but warn
        warn "Setting session key '$key' that starts with underscore";
    }

    $self->{data}{$key} = $value;
    $self->_save();
    return $value;
}

sub delete {
    my ($self, $key) = @_;

    # Don't allow deleting internal keys
    if ($key =~ /^_(created|modified|expire)$/) {
        warn "Cannot delete internal session key '$key'";
        return;
    }

    my $value = delete $self->{data}{$key};
    $self->_save();
    return $value;
}

sub keys {
    my ($self) = @_;
    return grep { !/^_/ } keys %{$self->{data}};
}

sub all_data {
    my ($self) = @_;
    my %user_data;
    for my $key ($self->keys()) {
        $user_data{$key} = $self->{data}{$key};
    }
    return \%user_data;
}

sub session_id {
    my ($self) = @_;
    return $self->{session_id};
}

sub is_new {
    my ($self) = @_;
    return $self->{is_new};
}

sub destroy {
    my ($self) = @_;
    my $file = $self->_session_file_path();
    unlink $file if -f $file;
    $self->{data} = {};
    $self->{session_id} = undef;
}

sub cookie {
    my ($self) = @_;
    return CGI::Cookie->new(
        -name     => $self->{cookie_name},
        -value    => $self->{session_id},
        -expires  => '+' . $self->{expire} . 's',
        -path     => '/',
        -httponly  => 1,
        -secure   => ($ENV{HTTPS} ? 1 : 0),
        -samesite => 'Strict',
    );
}

sub flush {
    my ($self) = @_;
    $self->_save();
}

sub _cleanup_expired {
    my ($self) = @_;
    my $dir = $self->{session_dir};
    my $prefix = $self->{session_prefix};

    opendir(my $dh, $dir) or return;
    my @files = grep { /^\Q$prefix\E[a-f0-9]{64}$/ } readdir($dh);
    closedir($dh);

    for my $file (@files) {
        my $path = File::Spec->catfile($dir, $file);
        eval {
            my $data = Storable::retrieve($path);
            if ($data && $data->{_modified}) {
                my $expire = $data->{_expire} || $self->{expire};
                if ((time() - $data->{_modified}) > $expire) {
                    unlink $path;
                }
            }
        };
        if ($@) {
            # Corrupted session file, remove it
            unlink $path;
        }
    }
}

# --- Main Application Demo ---
package main;

# Create CGI object
my $cgi = CGI->new();

# Initialize session
my $session = Session->new(
    cgi        => $cgi,
    session_dir => $SESSION_DIR,
    expire      => $SESSION_EXPIRE,
);

# Get the session cookie to send to client
