    my $key   = $cgi->param('key')   || '';
    my $value = $cgi->param('value') || '';
    if ($key && $key !~ /^_/) {
        $session->set($key, $value);
    }
} elsif ($action eq 'delete') {
    my $key = $cgi->param('key') || '';
    if ($key) {
        $session->delete($key);
    }
} elsif ($action eq 'destroy') {
    $session->destroy();
    # Create a fresh session after destroying
    $session = Session->new(
        cgi        => $cgi,
        session_dir => $SESSION_DIR,
        expire      => $SESSION_EXPIRE,
    );
